}

/* Mantener clics y foco normal (el pseudo no captura eventos) */
[selector="list-record-correos-adicionales"] .actions .popover-content p::after,
[selector="list-record-correos-adicionales"] .actions .popover-content .btn::after {
  pointer-events: none;
